// Build the PATCH body per action.
const r = $json;
const body = {};
if (r.action === 'pause') body.status = 'PAUSED';
if (r.action === 'scale_up') {
  const delta = Number(r.delta || 0.2);
  const currentMinor = Number(r.dailyBudgetMinor || 0);
  if (currentMinor <= 0) {
    return [{ json: { ...r, _skip: true, _skipReason: 'no current daily_budget' } }];
  }
  body.daily_budget = Math.round(currentMinor * (1 + delta));
}
return [{ json: { ...r, _body: body, attempt: 0, maxAttempts: 3, backoffMs: [2000, 4000, 8000] } }];

// Backoff branch — same retry-with-backoff logic as the shipped template.
const s = $input.first().json;
const nextAttempt = (s.attempt ?? 0) + 1;
if (nextAttempt > s.maxAttempts) {
  return [{ json: { ...s, attempt: nextAttempt, exhausted: true } }];
}
return [{ json: { ...s, attempt: nextAttempt, waitMs: s.backoffMs[nextAttempt - 1] } }];
